description:
Using `any` disables type checking entirely and lets type errors propagate silently. Use `unknown` instead — it forces you to narrow the type before using the value.

```typescript
// Bad — any disables all checking
function parse(input: any) {
  return input.name.toUpperCase(); // no error, crashes at runtime
}

// Good — unknown forces narrowing
function parse(input: unknown) {
  if (typeof input === 'object' && input !== null && 'name' in input) {
    return (input as { name: string }).name.toUpperCase();
  }
  throw new Error('Invalid input');
}
```

Model mutually exclusive states with a shared literal discriminant field. This eliminates impossible states and gives exhaustive narrowing in switch/if blocks.

```typescript
type AsyncState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: Error };

function render(state: AsyncState<User>) {
  switch (state.status) {
    case 'idle':    return 'Ready';
    case 'loading': return 'Loading...';
    case 'success': return state.data.name; // data is narrowed
    case 'error':   return state.error.message; // error is narrowed
  }
}
```

Use custom type guard functions (returning `x is T`) to encapsulate complex narrowing logic. This keeps calling code clean and the guard reusable.

```typescript
interface Dog { kind: 'dog'; bark(): void }
interface Cat { kind: 'cat'; meow(): void }
type Animal = Dog | Cat;

// Type guard function
function isDog(animal: Animal): animal is Dog {
  return animal.kind === 'dog';
}

function interact(animal: Animal) {
  if (isDog(animal)) {
    animal.bark(); // narrowed to Dog
  } else {
    animal.meow(); // narrowed to Cat
  }
}
```

Use `as const` to infer the narrowest possible type — literal values instead of widened primitives, and readonly tuples instead of mutable arrays.

```typescript
// Without as const — widened to { method: string; url: string }
const config = { method: 'GET', url: '/api' };

// With as const — literal types, fully readonly
const config = { method: 'GET', url: '/api' } as const;
// type: { readonly method: 'GET'; readonly url: '/api' }

// Great for defining route maps, action types, options
const ROLES = ['admin', 'editor', 'viewer'] as const;
type Role = (typeof ROLES)[number]; // 'admin' | 'editor' | 'viewer'
```

Use `extends` to constrain generic type parameters. This ensures the generic has the shape you need while keeping the function flexible.

```typescript
// Unconstrained — T could be anything
function getLength<T>(item: T): number {
  return item.length; // Error: Property 'length' does not exist
}

// Constrained — T must have a length property
function getLength<T extends { length: number }>(item: T): number {
  return item.length; // OK
}

// Constrained to keys of an object
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}
```

Use mapped types to systematically transform one type into another. They iterate over keys and apply modifications.

```typescript
// Make all properties optional and nullable
type Patchable<T> = {
  [K in keyof T]?: T[K] | null;
};

// Create a getter interface from a type
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};

interface User { name: string; age: number }
type UserGetters = Getters<User>;
// { getName: () => string; getAge: () => number }
```

Use template literal types to create string patterns at the type level. They combine with mapped types for powerful API designs.

```typescript
type EventName = 'click' | 'focus' | 'blur';
type Handler = `on${Capitalize<EventName>}`;
// 'onClick' | 'onFocus' | 'onBlur'

// CSS unit type
type CSSUnit = 'px' | 'rem' | 'em' | '%';
type CSSValue = `${number}${CSSUnit}`;

const width: CSSValue = '100px';  // OK
const bad: CSSValue = '100vw';    // Error

// Route parameters
type ExtractParams<T extends string> =
  T extends `${string}:${infer Param}/${infer Rest}`
    ? Param | ExtractParams<Rest>
    : T extends `${string}:${infer Param}` ? Param : never;

type Params = ExtractParams<'/users/:id/posts/:postId'>;
// 'id' | 'postId'
```

Use `satisfies` to validate that an expression matches a type while keeping the narrowest inferred type. Unlike type annotations, it does not widen the type.

```typescript
type Colors = Record<string, [number, number, number] | string>;

// With annotation — widened, loses specifics
const palette: Colors = { red: [255, 0, 0], blue: '#0000ff' };
palette.red.map(x => x); // Error: string | number[] has no .map

// With satisfies — validated but narrow
const palette = {
  red: [255, 0, 0],
  blue: '#0000ff',
} satisfies Colors;
palette.red.map(x => x);     // OK — inferred as [number, number, number]
palette.blue.toUpperCase();  // OK — inferred as string
```

Enable strict mode and additional safety flags. These catch real bugs at compile time.

```jsonc
// tsconfig.json
{
  "compilerOptions": {
    "strict": true,
    // Catches obj.arr[0] being possibly undefined
    "noUncheckedIndexedAccess": true,
    // Distinguishes between missing and undefined properties
    "exactOptionalPropertyTypes": true,
    // Prevents falling through switch cases
    "noFallthroughCasesInSwitch": true,
    // Catches unreachable code
    "noUnusedLocals": true,
    "noUnusedParameters": true
  }
}
```

`strict: true` enables `strictNullChecks`, `strictFunctionTypes`, `strictBindCallApply`, `strictPropertyInitialization`, `noImplicitAny`, `noImplicitThis`, `alwaysStrict`, and `useUnknownInCatchVariables`.

Use branded (opaque) types to prevent mixing up values that share the same primitive type but have different domain meanings.

```typescript
type Brand<T, B extends string> = T & { readonly __brand: B };

type UserId = Brand<string, 'UserId'>;
type OrderId = Brand<string, 'OrderId'>;

function getUser(id: UserId) { /* ... */ }
function getOrder(id: OrderId) { /* ... */ }

const userId = 'usr_123' as UserId;
const orderId = 'ord_456' as OrderId;

getUser(userId);   // OK
getUser(orderId);  // Error — OrderId is not assignable to UserId
```

Use branded types for IDs, monetary values, validated strings, and any domain concept where mixing values would be a bug.

Use the `never` type to ensure switch statements handle all union members. If a new variant is added, the code fails to compile until you handle it.

```typescript
type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'rect'; width: number; height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle': return Math.PI * shape.radius ** 2;
    case 'rect':   return shape.width * shape.height;
    default: {
      const _exhaustive: never = shape;
      throw new Error(`Unhandled shape: ${_exhaustive}`);
    }
  }
}
// Adding { kind: 'triangle'; ... } to Shape will cause
// a compile error at the never assignment
```

TypeScript enums have surprising runtime behavior, poor tree-shaking, and nominal typing quirks. Use `as const` objects with derived types instead.

```typescript
// Bad — enum generates runtime code, has quirks
enum Status {
  Active = 'active',
  Inactive = 'inactive',
}

// Good — plain object, tree-shakeable, predictable
const Status = {
  Active: 'active',
  Inactive: 'inactive',
} as const;

type Status = (typeof Status)[keyof typeof Status];
// 'active' | 'inactive'

// Usage is identical
function setStatus(s: Status) { /* ... */ }
setStatus(Status.Active);
```

Use built-in utility types instead of manually writing type transformations.

```typescript
interface User {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'user';
}

// Pick specific fields
type UserPreview = Pick<User, 'id' | 'name'>;

// Omit fields
type CreateUser = Omit<User, 'id'>;

// All optional (for PATCH endpoints)
type UpdateUser = Partial<User>;

// All required (undo Partial)
type CompleteUser = Required<User>;

// Key-value map
type UsersByRole = Record<User['role'], User[]>;

// Extract/Exclude from unions
type AdminRole = Extract<User['role'], 'admin'>; // 'admin'
type NonAdmin = Exclude<User['role'], 'admin'>;  // 'user'

// Return type of a function
type ParseResult = ReturnType<typeof JSON.parse>;

// Constructor parameter types
type DateArgs = ConstructorParameters<typeof Date>;
```

Use function overloads when a function has distinct input-output type relationships. Prefer union parameters when inputs and outputs are independent.

```typescript
// Good use of overloads — return type depends on input
function createElement(tag: 'input'): HTMLInputElement;
function createElement(tag: 'div'): HTMLDivElement;
function createElement(tag: string): HTMLElement;
function createElement(tag: string): HTMLElement {
  return document.createElement(tag);
}

const input = createElement('input'); // HTMLInputElement
const div = createElement('div');     // HTMLDivElement

// Bad use of overloads — union parameter is simpler
// Don't:
function format(value: string): string;
function format(value: number): string;
function format(value: string | number): string { /* ... */ }
// Do:
function format(value: string | number): string { /* ... */ }
```

Use module augmentation to add types to existing modules without modifying them. This is essential for extending libraries, adding global types, or patching missing declarations.

```typescript
// Extend Express Request with custom properties
declare module 'express' {
  interface Request {
    user?: { id: string; role: string };
    requestId: string;
  }
}

// Extend a library's theme type
declare module '@emotion/react' {
  export interface Theme {
    colors: { primary: string; background: string };
    spacing: (n: number) => string;
  }
}

// Add global type declarations
declare global {
  interface Window {
    analytics: AnalyticsClient;
  }
}
```

Place augmentations in a `.d.ts` file included in your tsconfig. Keep them co-located with the feature that needs them.

The `!` non-null assertion operator tells TypeScript to trust you that a value is not null/undefined. Overusing it defeats the purpose of strict null checks and hides real bugs.

```typescript
// Bad — blindly asserting non-null
const el = document.querySelector('.btn')!;
el.addEventListener('click', handler); // crashes if element missing

// Good — handle the null case
const el = document.querySelector('.btn');
if (el) {
  el.addEventListener('click', handler);
}

// Acceptable — when you have a structural guarantee
class Component {
  private root!: HTMLElement; // assigned in mount(), called before use
  mount(el: HTMLElement) { this.root = el; }
}
```

Reserve `!` for cases where you have a structural guarantee the value exists (e.g., class lifecycle). Prefer narrowing or optional chaining everywhere else.

Let TypeScript infer return types for internal functions — it reduces noise and stays in sync. Explicitly annotate return types on exported/public API functions to prevent accidental changes.

```typescript
// Internal — let TS infer the return type
function calculateTotal(items: CartItem[]) {
  return items.reduce((sum, item) => sum + item.price * item.qty, 0);
}

// Public API — annotate to lock the contract
export function createUser(input: CreateUserInput): Promise<User> {
  // If implementation accidentally returns something else,
  // TS catches it here instead of at every call site
}

// Library boundary — always annotate
export interface UserService {
  getUser(id: UserId): Promise<User | null>;
  listUsers(filter: UserFilter): Promise<User[]>;
}
```

Avoid `as T` casts to force a type. They bypass the type checker and can hide real mismatches. Use type narrowing (guards, `in`, `instanceof`, `typeof`) to let TypeScript verify correctness.

```typescript
// Bad — assertion hides a potential mismatch
const user = fetchData() as User;

// Good — runtime check proves the type
function isUser(data: unknown): data is User {
  return (
    typeof data === 'object' &&
    data !== null &&
    'id' in data &&
    'name' in data
  );
}

const data = fetchData();
if (isUser(data)) {
  console.log(data.name); // safely narrowed
}
```

Legitimate uses of `as`: branded type constructors, test fixtures, and narrowing from a validated schema (e.g., Zod `.parse()`).
